INSERT INTO public.terms_conditions(title,body,locale,is_default,sort_order) VALUES
('Standard Terms','This estimate is valid for 30 days from the date of issue. Prices are subject to change based on final material selections and site conditions. A signed contract and deposit are required to schedule work. Any changes to the scope of work will be documented as a change order.','en',true,1),
('标准条款','此报价单自签发之日起30天内有效。最终价格可能因材料选择及现场情况而调整。开工前需签订正式合同并支付定金。任何工程范围变更将以书面变更单形式确认。','zh',true,2)
